核心改动示例（概念性）：
1) 预处理阶段构建 CSR：
  std::vector<int> rowPtr(nrow+1);
  std::vector<local_int_t> colInd(nnz);
  std::vector<double> val(nnz);
  // 将原 A.matrixValues[i], A.mtxIndL[i] 拷贝/打包到连续内存
2) SpMV 内核改为：
  for i in [0,nrow):
    double sum=0;
    for (k=rowPtr[i]; k<rowPtr[i+1]; ++k)
      sum += val[k]*xv[colInd[k]];
    yv[i]=sum;
3) 若采用 SELL-C-σ：按行长度分桶并按 C 行打包，内层对 C 行做SIMD/warp协同加载。
注意：HPCG 基准“ref 版本不可改”，但在真实应用/非 ref 路径可实现同等数学结果的优化内核（例如 ComputeSPMV 优化版）。

1) 指针限定（若可改接口/实现）：
  const double* __restrict xv = x.values;
  double* __restrict yv = y.values;
2) 内层：
  #pragma omp simd reduction(+:sum)
  for (int j=0; j<cur_nnz; ++j) ...
3) 预取（谨慎）：
  __builtin_prefetch(&xv[cur_inds[j+P]], 0, 1);
说明：由于 gather 不规则，SIMD/预取收益通常受限。

1) 将 ExchangeHalo 拆分为：post_receives/post_sends + pack + start + wait。
2) 在 ComputeSPMV 中：
  ExchangeHaloStart(A,x,reqs);
  SpMV_interior_rows(); // 仅使用本地 x 的行
  ExchangeHaloWait(reqs);
  SpMV_boundary_rows();
3) 需要预先标记 interior/boundary 行集合（按列索引是否落在外部区间）。

1) 在 SparseMatrix 构建阶段新增: std::vector<double> diag(nrow); for i: diag[i]=*(A.matrixDiagonal[i]); 并在 kernel 中用 const double currentDiagonal = A.diag[i];
2) 若 localNumberOfColumns < 2^31：将 mtxIndL 的元素类型改为 int32_t（或在 kernel 内将 local_int_t* 换为 int32_t*），并确保 ExchangeHalo/装配一致。
3) 将 currentNumberOfNonzeros 提前取到寄存器并用 size_t/ int 统一，避免隐式转换。

在矩阵初始化时：invDiag[i]=1.0/diag[i]。
kernel 中替换：xv[i] = sum * invDiag[i];
并将内层写为：sum = std::fma(-currentValues[j], xv[curCol], sum);（或依赖编译器 -ffp-contract=fast）。

1) 添加 restrict/[[gnu::assume_aligned]]（若可保证）:
const double* __restrict currentValues; const local_int_t* __restrict currentColIndices; double* __restrict xv;
2) 在 j 循环中对未来的 xv[curCol] 做预取（经验性）：
__builtin_prefetch(&xv[currentColIndices[j+P]], 0, 1);
P 取 8~32 试验。
3) 编译选项：-O3 -march=native（或等价），并评估 -ffast-math 对数值影响（HPCG 通常不建议改变数值语义）。

示例改动(核心思想)：

1) 预计算常量：
const double stepCap = step / Cap;
const double cRx = stepCap * (1.0/Rx);
const double cRy = stepCap * (1.0/Ry);
const double cRz = stepCap * (1.0/Rz);
const double cC  = stepCap * (-2.0*(1.0/Rx) - 2.0*(1.0/Ry) - (1.0/Rz));
const double cAmb = stepCap * (80.0*(1.0/Rz));

2) 内部区域无分支：
for (int i=1;i<row-1;i++) {
  const int base = i*col;
  const int baseN = (i-1)*col;
  const int baseS = (i+1)*col;
  #pragma omp simd
  for (int j=1;j<col-1;j++) {
    const int idx = base + j;
    const double tC = temp[idx];
    const double tE = temp[idx+1];
    const double tW = temp[idx-1];
    const double tN = temp[baseN+j];
    const double tS = temp[baseS+j];
    const double p  = power[idx];
    // 线性组合，减少括号与重复访存
    const double delta = stepCap*p + cRx*(tE+tW) + cRy*(tN+tS) + cC*tC + cAmb;
    result[idx] = tC + delta;
  }
}

3) 边界单独处理(四条边+四角)，保持正确性但不污染主循环。

空间块：按 i 方向分块，保持三行(temp[i-1],temp[i],temp[i+1])在更高层缓存中复用：
for (int ii=1; ii<row-1; ii+=Bi) {
  int iend = min(ii+Bi, row-1);
  for (int i=ii; i<iend; i++) { ... 内部j循环 ... }
}
并在 i 循环内缓存行指针：
const double* tN = temp + (i-1)*col;
const double* tC = temp + i*col;
const double* tS = temp + (i+1)*col;
double* rC = result + i*col;
const double* pC = power + i*col;

时间阻塞（更难）：一次在小tile上做2+步迭代以减少读写往返，但需要额外halo与更复杂的边界同步。

在 Phase 1：
- 预计算 invI = 1.0 / image[idx]，invI2 = invI * invI，替代 (..)/(image[idx]*image[idx]) 与 (..)/image[idx]
- 将 (1.0 + 0.25*L) 记为 t，den = t*t
- 将常数 0.5、1/16、0.25 用编译期常量并尽量让编译器生成 FMA
- 用 fmax/fmin 替代分支 clamp（利于 SIMD）：c = fmin(1.0, fmax(0.0, c))
- 避免重复索引计算：row = i*cols；idx=row+j；邻居 idxN/idxS/idxW/idxE 直接算
示例片段：
const double eps=1e-15;
I = image[idx]; invI = 1.0/I; invI2 = invI*invI;
G2 = (dN*dN + dS*dS + dW*dW + dE*dE) * invI2;
L  = (dN + dS + dW + dE) * invI;
t = 1.0 + 0.25*L; den = t*t;
qsqr = (0.5*G2 - (1.0/16.0)*(L*L)) / (den + eps);
den2 = (qsqr - q0sqr) / (q0sqr*(1.0+q0sqr));
c = 1.0 / (1.0 + den2);
c = fmin(1.0, fmax(0.0, c));

1) 将 hgcoef 移到 mode 循环外（当前每mode重复计算且与mode无关）：
```cpp
const double volume = elemMass[i] / ss[i];
const double volinv = 1.0 / (volume + 1e-20);
const double hgcoef = HGCOEF * ss[i] * elemMass[i] * volinv; // moved out
for (int mode=0; mode<4; ++mode) { ... use hgcoef ... }
```
2) 将 gamma 展开为 int8/short 常量并用乘法替换为加减（gamma仅±1）：
```cpp
// precompute sign as int8_t gammaS[4][8] = {+1,+1,-1,...}
// hourmodx += xd_local[n] * gamma -> if(gamma==1) += xd_local[n] else -= xd_local[n]
```
3) 对 n=0..7 的小循环手工展开或用 `#pragma unroll`（CPU编译器常能展开，但显式更稳）：
```cpp
#pragma unroll
for(int n=0;n<8;++n){...}
```
4) 使用 restrict/assume-aligned 帮助编译器向量化：
```cpp
void CalcFBHourglassForceForElems(const double* __restrict xd, ...,
                                 double* __restrict fx, ...)
```
并在分配后对齐（posix_memalign/ aligned_alloc）。

方案A（推荐，node-centric）：预构建 node->elements 邻接表（CSR），每个节点线程负责累加其相邻单元贡献，避免原子。
- 预处理：构建 `nodeElemPtr[node+1]` 与 `nodeElemIdx[]`，以及该节点在单元内的局部索引 `nodeElemLocalCorner[]`。
- 计算：
```cpp
#pragma omp parallel for
for(int node=0; node<NUM_NODES; ++node){
  double fxn=0,fyn=0,fzn=0;
  for(int t=nodeElemPtr[node]; t<nodeElemPtr[node+1]; ++t){
    int e = nodeElemIdx[t];
    int corner = nodeElemLocalCorner[t];
    // 需要能得到该element对该corner的hgfx/hgfy/hgfz贡献
    // 可将每element的4个mode投影先算出，再按corner累加
  }
  fx[node]+=fxn; fy[node]+=fyn; fz[node]+=fzn;
}
```
方案B（较易落地）：OpenMP element并行 + 原子累加（正确但慢）：
```cpp
#pragma omp parallel for
for(i=0;i<numElem;++i){... 
  #pragma omp atomic
  fx[gnode]+=hgfx[n];
}
```
方案C：线程私有节点力缓冲（分块/哈希）+ 最后归并，减少原子频率。

将多个 if 合并为掩码式选择（编译器更易向量化），并避免 fabs 分支：
```cpp
#pragma omp simd
for(int i=0;i<numElem;++i){
  double c1s = 2.0/3.0;
  double bvc = c1s*(compression[i]+1.0);
  double pi = bvc*vnew[i];
  // mask
  pi = (fabs(pi) < p_cut) ? 0.0 : pi;
  pi = (vnew[i] >= 1.0) ? 0.0 : pi;
  pi = (pi < pmin) ? pmin : pi;
  p[i]=pi;
}
```
若允许fast-math，可用 `fmax`/`copysign` 等进一步减少分支。

1) 为指针添加 restrict 并提示对齐，减少别名阻碍：
```cpp
void sparse_matvec(int n,
  const int * __restrict rowptr,
  const int * __restrict colidx,
  const double * __restrict values,
  const double * __restrict x,
  double * __restrict y)
{
  #pragma omp parallel for schedule(static)
  for (int i=0;i<n;i++) {
    double sum=0.0;
    int start=rowptr[i], end=rowptr[i+1];
    #pragma omp simd reduction(+:sum)
    for (int j=start;j<end;j++) {
      sum += values[j] * x[colidx[j]];
    }
    y[i]=sum;
  }
}
```
2) 若矩阵结构接近固定带宽（本生成器确实是 banded），可改为“带宽SpMV”避免 colidx：存储每行固定偏移（-NONZER..+NONZER）与对应 values，内层直接 x[i+offset]，完全规则访问。
3) 若必须保留稀疏通用性：将 CSR 转换为 SELL-C-σ（按行分桶、行内填充到 C 的倍数）或 ELL（当每行 nnz 近似固定时），以提升连续性与 SIMD/GPU 合并访问。

```cpp
double dot_product(const double* __restrict x,
                   const double* __restrict y,
                   int n)
{
  double sum = 0.0;
  #pragma omp parallel for simd reduction(+:sum) schedule(static)
  for (int i=0;i<n;i++) sum += x[i]*y[i];
  return sum;
}
```
若需要更高吞吐，可做手动分块累加（多个局部累加器）以减少依赖链。

1) conj_grad 内 r/p/q 每次 calloc/free 代价高（尤其外层 NITER 次调用）。改为在 main 里一次性分配并复用，或在 conj_grad 外传入工作区：
```cpp
// main: 分配 r,p,q,ax 并复用
// conj_grad(..., double* r, double* p, double* q)
```
2) 融合更新：将两次 axpy 合并为单循环（减少一次读写 x/r/q/p 的流量）：
```cpp
#pragma omp parallel for schedule(static)
for (int i=0;i<n;i++) {
  x[i] += alpha * p[i];
  r[i] -= alpha * q[i];
}
```
3) p 更新同样并行：
```cpp
#pragma omp parallel for schedule(static)
for (int i=0;i<n;i++) p[i] = r[i] + beta*p[i];
```

1) 为指针添加 restrict 并保证对齐分配（aligned_alloc/posix_memalign）。
2) 将 i*n 提前计算为行指针，减少乘法与重复索引。
3) OpenMP 并行外层 i 循环，并用 simd 指令提示内层 j 向量化。

示例改动：
```cpp
#include <omp.h>

void jacobi_kernel(int tsteps, int n, double * __restrict A, double * __restrict B){
  for(int t=0;t<tsteps;t++){
    #pragma omp parallel for schedule(static)
    for(int i=1;i<n-1;i++){
      const double* __restrict Ai   = A + i*n;
      const double* __restrict Aim1 = A + (i-1)*n;
      const double* __restrict Aip1 = A + (i+1)*n;
      double* __restrict Bi = B + i*n;
      #pragma omp simd
      for(int j=1;j<n-1;j++){
        Bi[j] = 0.2*(Ai[j] + Ai[j-1] + Ai[j+1] + Aip1[j] + Aim1[j]);
      }
    }
    #pragma omp parallel for schedule(static)
    for(int i=1;i<n-1;i++){
      const double* __restrict Bi   = B + i*n;
      const double* __restrict Bim1 = B + (i-1)*n;
      const double* __restrict Bip1 = B + (i+1)*n;
      double* __restrict Ai = A + i*n;
      #pragma omp simd
      for(int j=1;j<n-1;j++){
        Ai[j] = 0.2*(Bi[j] + Bi[j-1] + Bi[j+1] + Bip1[j] + Bim1[j]);
      }
    }
  }
}
```
分配对齐：
```cpp
posix_memalign((void**)&A, 64, n*n*sizeof(double));
posix_memalign((void**)&B, 64, n*n*sizeof(double));
```
编译建议：`-O3 -march=native -ffast-math -fopenmp`（或等价）。

```cpp
#pragma omp parallel for reduction(+:residual) schedule(static)
for(i=1;i<n-1;i++){
  const double* Ai=A+i*n; const double* Aim1=A+(i-1)*n; const double* Aip1=A+(i+1)*n;
  #pragma omp simd reduction(+:residual)
  for(j=1;j<n-1;j++){
    double lap = Aim1[j]+Aip1[j]+Ai[j-1]+Ai[j+1]-4.0*Ai[j];
    residual += lap*lap;
  }
}
```
checksum 同理 reduction。

将三重循环改为分块：for (ii) for (jj) { 先对 C[ii:ii+Ti][jj:jj+Tj] 做 beta 缩放；for (kk) 取 A block 与 B block，使用小块 (例如 8x8 或 8x16) 在寄存器中累加 C 子块；最后写回 C 子块 }。示例骨架：

const int Ti=64, Tj=64, Tk=64;
for (int ii=0; ii<ni; ii+=Ti)
  for (int jj=0; jj<nj; jj+=Tj) {
    int iimax = (ii+Ti<ni)? ii+Ti: ni;
    int jjmax = (jj+Tj<nj)? jj+Tj: nj;
    for (int i=ii;i<iimax;i++)
      for (int j=jj;j<jjmax;j++) C[i][j]*=beta;
    for (int kk=0; kk<nk; kk+=Tk) {
      int kkmax=(kk+Tk<nk)? kk+Tk: nk;
      for (int i=ii;i<iimax;i++) {
        for (int j=jj;j<jjmax;j+=8) {
          DATA_TYPE c0=C[i][j+0], c1=C[i][j+1], ... c7=C[i][j+7];
          for (int k=kk;k<kkmax;k++) {
            DATA_TYPE a = alpha*A[i][k];
            c0 += a*B[k][j+0]; ... c7 += a*B[k][j+7];
          }
          C[i][j+0]=c0; ... C[i][j+7]=c7;
        }
      }
    }
  }

(注意处理 j+lane 越界；Ti/Tj/Tk 需按 L1/L2/LLC 与数据类型调参)

在分块版本上对 (ii,jj) 进行 collapse 并行：

#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<ni; ii+=Ti)
  for (int jj=0; jj<nj; jj+=Tj) {
    ... // 每个线程独占一个 C 子块
  }

若不分块，至少可：
#pragma omp parallel for schedule(static)
for (int i=0;i<ni;i++) { ... }

并确保编译时开启 -fopenmp。

1) 给指针加 restrict（PolyBench 宏可能阻碍别名分析，可在 kernel 内部创建 restrict 指针）：
DATA_TYPE (* __restrict c)[NJ] = C;
DATA_TYPE (* __restrict a)[NK] = A;
DATA_TYPE (* __restrict b)[NJ] = B;

2) 对内层 j 循环加向量化提示并保证对齐：
#pragma omp simd aligned(c,b:64)
for (int j=jj; j<jjmax; j++) c[i][j] += a_ik * b[k][j];

3) 或在 micro-kernel 中用 _mm256/_mm512 FMA 做 8/16 路累加。

在进入 kernel 前构造 BT[j][k]=B[k][j]（或按块打包 Bpack[kk:kk+Tk][jj:jj+Tj] 为连续布局）。然后内核使用 BT 使得对 k 的访问更连续（取决于 micro-kernel 设计）。示例（全转置，额外内存 O(NK*NJ)）：
for k in [0..nk) for j in [0..nj) BT[j][k]=B[k][j];
内核改为：C[i][j] += alpha*A[i][k]*BT[j][k];

更推荐按块 packing，避免一次性大转置带来的额外带宽与缓存污染。

用 cblas_dgemm/sgemm 替换 kernel_gemm：
// C = alpha*A*B + beta*C
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans,
            ni, nj, nk, alpha, &A[0][0], nk, &B[0][0], nj, beta, &C[0][0], nj);

并链接对应 BLAS 库。

示例（保持语义，展示关键结构；实际块大小需按缓存调参）：

// 建议添加 restrict/对齐（见后续条目）
const int BI=32, BJ=64, BK=32;
for (int ii=0; ii<_PB_NI; ii+=BI)
  for (int jj=0; jj<_PB_NJ; jj+=BJ) {
    // 初始化 tmp block
    for (int i=ii; i<min(ii+BI,_PB_NI); ++i)
