与E类似，将(NJ,NL,NM)对应到(i,j,k)并分块：

const int Ti=64, Tj=64, Tk=64;
#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<_PB_NJ; ii+=Ti)
  for (int jj=0; jj<_PB_NL; jj+=Tj) {
    for (int i=ii; i<min(ii+Ti,_PB_NJ); ++i)
      for (int j=jj; j<min(jj+Tj,_PB_NL); ++j)
        F[i][j]=0;
    for (int kk=0; kk<_PB_NM; kk+=Tk)
      for (int i=ii; i<min(ii+Ti,_PB_NJ); ++i)
        for (int k=kk; k<min(kk+Tk,_PB_NM); ++k) {
          DATA_TYPE cik = C[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+Tj,_PB_NL); ++j)
            F[i][j] += cik * D[k][j];
        }
  }

可选: Dt[j][k]=D[k][j]，将内层访问改为Dt[j][k]以获得连续读。

基础分块(同前)：

const int Ti=64, Tj=64, Tk=64;
#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<_PB_NI; ii+=Ti)
  for (int jj=0; jj<_PB_NL; jj+=Tj) {
    for (int i=ii; i<min(ii+Ti,_PB_NI); ++i)
      for (int j=jj; j<min(jj+Tj,_PB_NL); ++j)
        G[i][j]=0;
    for (int kk=0; kk<_PB_NJ; kk+=Tk)
      for (int i=ii; i<min(ii+Ti,_PB_NI); ++i)
        for (int k=kk; k<min(kk+Tk,_PB_NJ); ++k) {
          DATA_TYPE eik = E[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+Tj,_PB_NL); ++j)
            G[i][j] += eik * F[k][j];
        }
  }

高级(难): 通过算子融合减少E/F的写回与读回：
G = (A*B)*(C*D) 可用分块流水：对G的一个tile，先计算所需的E_tile与F_tile(或其k块)到L2/L1缓冲，再累加到G_tile，避免完整E/F落内存。实现复杂且需额外临时缓冲与调度。

最佳实践: 直接调用BLAS三次gemm：cblas_*gemm(...)，让库完成微内核/打包/NUMA优化。

将内层更新改为对每个 (i,j) 先在寄存器累加 sum，再一次性写回 C；并把 k 放到最内层以便 A[j][k] 连续：

for (i=0;i<_PB_N;i++) {
  for (j=0;j<=i;j++) {
    DATA_TYPE sum = 0;
    for (k=0;k<_PB_M;k++) sum += A[i][k]*A[j][k];
    C[i][j] = beta*C[i][j] + alpha*sum;
  }
}

（可进一步对 j 做分块以提升 A[j][k] 的复用）

示意（块大小 BI,BJ 依据 L1/L2 调参）：

for (ii=0; ii<N; ii+=BI)
  for (jj=0; jj<=ii; jj+=BJ) {
    int i_max=min(ii+BI,N);
    int j_max=min(jj+BJ,N);
    for (i=ii;i<i_max;i++)
      for (j=jj;j<j_max && j<=i;j++) {
        DATA_TYPE sum=0;
        #pragma omp simd reduction(+:sum)
        for (k=0;k<M;k++) sum += A[i][k]*A[j][k];
        C[i][j]=beta*C[i][j]+alpha*sum;
      }
  }

可选：对 A 做“面板打包”（pack A[j][k] 的连续块到临时缓冲）以避免跨行步长访问。

在 i 或 ii 上并行：

#pragma omp parallel for schedule(static)
for (i=0;i<_PB_N;i++) {
  for (j=0;j<=i;j++) {
    DATA_TYPE sum=0;
    #pragma omp simd reduction(+:sum)
    for (k=0;k<_PB_M;k++) sum += A[i][k]*A[j][k];
    C[i][j]=beta*C[i][j]+alpha*sum;
  }
}

若采用分块：对 ii 并行更利于缓存与负载均衡。

增加一次性转置（O(N*M)）并改用 AT：

// build AT[k][i] = A[i][k]
for (i=0;i<n;i++) for (k=0;k<m;k++) AT[k][i]=A[i][k];

// then sum over k: A[i][k]*A[j][k] becomes AT[k][i]*AT[k][j]
for (i=0;i<n;i++)
  for (j=0;j<=i;j++) {
    DATA_TYPE sum=0;
    #pragma omp simd reduction(+:sum)
    for (k=0;k<m;k++) sum += AT[k][i]*AT[k][j];
    C[i][j]=beta*C[i][j]+alpha*sum;
  }

AT 的 k 维连续、i/j 为小步长访问，通常更友好。

最简单：#pragma omp parallel for schedule(static) 放在 i 循环上（每个线程写不同的 C[i][0..i]，无冲突）：
#pragma omp parallel for schedule(static)
for (i=0; i<_PB_N; i++) { ... }
若采用 j 分块累加，可进一步在 (i,jb) 上 collapse：
#pragma omp parallel for collapse(2) schedule(static)
for (i=0; i<N; i++)
  for (jb=0; jb<=i; jb+=JB) { ... }
注意：collapse(2) 时每个 (i,jb) 写 C 的不重叠块，仍无冲突。

方案A（推荐）：预先构造 C4T[p][s]=C4[s][p]，内核改为 sum[p]+=A* C4T[p][s]，使内层 s 访问连续。

// 1) 分配并构造转置矩阵（一次性开销）
POLYBENCH_2D_ARRAY_DECL(C4T, DATA_TYPE, NP, NP, np, np);
for (int s=0; s<np; ++s)
  for (int p=0; p<np; ++p)
    C4T[p][s] = C4[s][p];

// 2) kernel 中使用 C4T
for (r=0; r<_PB_NR; r++)
  for (q=0; q<_PB_NQ; q++) {
    for (p=0; p<_PB_NP; p++) sum[p]=0;
    for (p=0; p<_PB_NP; p++) {
      DATA_TYPE acc = 0;
      for (s=0; s<_PB_NP; s++)
        acc += A[r][q][s] * C4T[p][s];
      sum[p] = acc;
    }
    for (p=0; p<_PB_NP; p++) A[r][q][p]=sum[p];
  }

方案B（不转置）：改为 s 外层，顺序访问 C4[s][p] 的整行并累加到 sum[p]（对 C4 行连续、对 sum 连续）：
for (p=0; p<NP; ++p) sum[p]=0;
for (s=0; s<NP; ++s) {
  DATA_TYPE a = A[r][q][s];
  #pragma omp simd
  for (p=0; p<NP; ++p)
    sum[p] += a * C4[s][p];
}
for (p=0; p<NP; ++p) A[r][q][p]=sum[p];

关键点：sum 当前是共享数组，会在不同 (r,q) 并行时产生数据竞争；需改为线程私有缓冲。

#pragma omp parallel
{
  DATA_TYPE *sum_priv = (DATA_TYPE*) aligned_alloc(64, np*sizeof(DATA_TYPE));
  #pragma omp for collapse(2) schedule(static)
  for (int r=0; r<_PB_NR; ++r)
    for (int q=0; q<_PB_NQ; ++q) {
      for (int p=0; p<_PB_NP; ++p) sum_priv[p]=0;
      for (int s=0; s<_PB_NP; ++s) {
        DATA_TYPE a = A[r][q][s];
        #pragma omp simd
        for (int p=0; p<_PB_NP; ++p)
          sum_priv[p] += a * C4[s][p];
      }
      for (int p=0; p<_PB_NP; ++p) A[r][q][p]=sum_priv[p];
    }
  free(sum_priv);
}

示例：按 p 分块（PB 为块大小，如 64/128，需按平台调参）：
for (int pb=0; pb<NP; pb+=PB) {
  int pend = min(NP, pb+PB);
  for (int p=pb; p<pend; ++p) sum[p]=0;
  for (int s=0; s<NP; ++s) {
    DATA_TYPE a = A[r][q][s];
    #pragma omp simd
    for (int p=pb; p<pend; ++p)
      sum[p] += a * C4[s][p];
  }
  for (int p=pb; p<pend; ++p) A[r][q][p]=sum[p];
}

