2) NUMA：在 init_array 中用相同的并行策略触发 first-touch（或在 main 中并行初始化 ex/ey/hz）。

对 i/j 做二维分块，使 hz/ex/ey 的相邻行在 LLC 中复用更好（尤其 hz 更新需要 ex[i][j+1]、ey[i+1][j]）：

```c
const int Bi=64, Bj=256; // 需按机器 LLC/带宽调参
for (t=0;t<tmax;t++) {
  for (int ii=1; ii<nx; ii+=Bi)
    for (int jj=0; jj<ny; jj+=Bj) {
      int iend = MIN(ii+Bi, nx);
      int jend = MIN(jj+Bj, ny);
      for (int i=ii;i<iend;i++)
        for (int j=jj;j<jend;j++)
          ey[i][j] -= cey*(hz[i][j]-hz[i-1][j]);
    }
  // ex/hz 同理（注意各自 j 起点/终点）
}
```

并与 OpenMP 结合：对 (ii,jj) 块并行 `#pragma omp for collapse(2)`。

在最内层循环中先加载中心点并复用；将 0.125*(x -2*c + y) 形式改写为 0.125*(x+y) + (1-0.75)*c 或直接合并系数，减少对 c 的重复引用并利于编译器生成 FMA。

示例（A->B 一段，B->A 同理）：
```cpp
for (i=1;i<_PB_N-1;i++)
  for (j=1;j<_PB_N-1;j++)
    for (k=1;k<_PB_N-1;k++) {
      DATA_TYPE c = A[i][j][k];
      DATA_TYPE sum = A[i+1][j][k] + A[i-1][j][k]
                    + A[i][j+1][k] + A[i][j-1][k]
                    + A[i][j][k+1] + A[i][j][k-1];
      // 原式等价：c + 0.125*(sum - 6*2? 注意原式为三方向各 -2*c，共 -6*c
      B[i][j][k] = c + (DATA_TYPE)0.125 * (sum - (DATA_TYPE)6.0 * c);
    }
```
（保持数值等价：原式三项各含 -2*c，总计 -6*c）

对 i/j 维并行（避免对 k 并行导致更差的写合并/更高开销），并在初始化阶段并行 first-touch 以匹配 NUMA。

```cpp
// init_array: 并行 first-touch
#pragma omp parallel for collapse(2) schedule(static)
for (int i=0;i<n;i++)
  for (int j=0;j<n;j++)
    for (int k=0;k<n;k++)
      A[i][j][k] = B[i][j][k] = ...;

// kernel: A->B
#pragma omp parallel for collapse(2) schedule(static)
for (int i=1;i<_PB_N-1;i++)
  for (int j=1;j<_PB_N-1;j++)
    for (int k=1;k<_PB_N-1;k++) { ... }

// kernel: B->A 同样并行
```
必要时加 `OMP_PROC_BIND=close`、`OMP_PLACES=cores`，并确保大页/NUMA 策略正确。

对 i/j/k 做分块，使一个 tile 的 3D 子块（含 halo）尽量驻留在 LLC/L2，减少跨行/跨平面反复从内存取数。示例（以 i/j 分块，k 保持内层连续）：
```cpp
const int Ti=16, Tj=16; // 需按缓存/数据类型调参
for (t=1;t<=TSTEPS;t++) {
  for (int ii=1; ii<_PB_N-1; ii+=Ti)
    for (int jj=1; jj<_PB_N-1; jj+=Tj)
      for (int i=ii; i<min(ii+Ti,_PB_N-1); i++)
        for (int j=jj; j<min(jj+Tj,_PB_N-1); j++)
          for (int k=1; k<_PB_N-1; k++) { /* A->B */ }
  // B->A 同样分块
}
```
块大小经验：让 (Ti*Tj*Nk_tile)*sizeof(DATA_TYPE) 及其 halo 在 LLC/L2 内；若 L2 较大可尝试 k 也分块（Tk=64/128）。

PolyBench 的 3D 宏可能阻碍编译器别名分析；可将 A/B 线性化为 1D 并使用 restrict 指针，保证 k 维连续并显式向量化。

示例（概念）：
```cpp
DATA_TYPE * __restrict A1 = &A[0][0][0];
DATA_TYPE * __restrict B1 = &B[0][0][0];
auto idx = [&](int i,int j,int k){ return (i*n + j)*n + k; };

#pragma omp parallel for collapse(2) schedule(static)
for (int i=1;i<n-1;i++)
  for (int j=1;j<n-1;j++) {
    #pragma omp simd
    for (int k=1;k<n-1;k++) {
      int p = idx(i,j,k);
      DATA_TYPE c = A1[p];
      DATA_TYPE sum = A1[p+n*n] + A1[p-n*n] + A1[p+n] + A1[p-n] + A1[p+1] + A1[p-1];
      B1[p] = c + (DATA_TYPE)0.125*(sum - (DATA_TYPE)6.0*c);
    }
  }
```
并确保分配对齐（如 64B）与编译选项 `-O3 -march=native -ffast-math`（若允许）。

方案A（Jacobi，最易并行）：新增数组 B，与 A 交替写入。

// 分配 B
POLYBENCH_2D_ARRAY_DECL(B, DATA_TYPE, N, N, n, n);

for (t=0; t<_PB_TSTEPS; t++) {
  for (i=1; i<=_PB_N-2; i++)
    for (j=1; j<=_PB_N-2; j++)
      B[i][j] = (A[i-1][j-1]+A[i-1][j]+A[i-1][j+1]
               + A[i][j-1]  +A[i][j]  +A[i][j+1]
               + A[i+1][j-1]+A[i+1][j]+A[i+1][j+1]) * (DATA_TYPE)(1.0/9.0);
  // swap(A,B)
  DATA_TYPE (*tmp)[N] = A; A = B; B = tmp;
}

